var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"좋은 아침임다, 할부지!","JPN":"おはようっす、爺ちゃん！","ENG":"Good morning, sir!","TWN":"早安，爺爺！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_ANIMAL_B"},{"id":"L6_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"으응? 누군가 했더니 모네구나? 그 낚싯대는 웬 거냐?","JPN":"おや？　モネじゃねえか。その釣竿はどうしたんじゃ？","ENG":"Huh? Oh, it's you, Mone. What's with the fishing rod?","TWN":"嗯？是莫妮啊！拿著釣魚竿幹什麼？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"엄니가 피곤하대서 고기를 잡아다 드리러 왔슴다!","JPN":"母ちゃんが元気がないって言うから釣りに来たっす！","ENG":"I'm here to catch some fish for my mama because she's not feelin' so well!","TWN":"媽媽說她有點疲累，所以我來抓幾條魚給她補補！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"두고 보십셔! 이—따만한 월척을 잡아다 드릴 검다!","JPN":"ふふーん！　今日は大物釣って母ちゃんにごちそうするっすよ！","ENG":"Just you wait and see! I'll catch her a humongous fish!","TWN":"您看著吧！我一定會釣到這——麼大的魚！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"욘석도 참. 벌써부터 엄마 먼저 챙기고 다 컸구나.","JPN":"親孝行できてえらいのぅ。もうすっかり大きくなったもんじゃ。","ENG":"Good lass. You're taking good care of your mom. You're all grown up!","TWN":"妳這傢伙，都會孝順媽媽了，真是長大了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"헤헷. 동네 언니 오빠들은 다들 모네 나이 때부터 일하러 가지 않았슴까.","JPN":"へへっ。でも他の家の姉ちゃん兄ちゃんたちも、モネくらいの歳になったら働きに出てるっすよ。","ENG":"Heh heh. Everyone else in the village already started working at my age.","TWN":"嘿嘿，村子裡的哥哥姐姐們像我這麼大的時候就出去工作了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"그래서 말인데 할부지, 혹시 바다 나가는 배 없슴까?","JPN":"ところで爺ちゃん。今日海に出る船はないっすか？","ENG":"So I was wondering, sir... Are there any boats headed out to sea today?","TWN":"對了，爺爺，有沒有出海的船啊？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"에그, 없지. 간밤에 저기 항만 쪽에서 총소리가 들려서 오늘은 다들 배 안 띄우려 할 텐데.","JPN":"ないんじゃないかのう。昨夜、港湾の方から銃声が聞こえたせいで、今日は船を出す人はおらんと思うのじゃ。","ENG":"Oh, I'm afraid not. We heard gunshots from the harbor last night. I doubt anyone wants to sail today.","TWN":"哎呀，沒有。昨晚從那邊的港灣傳來了槍聲，所以今天大家都不敢出海。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"엑, 진짜임까?","JPN":"ええーほんとっすか？","ENG":"Oh, no! Really?","TWN":"啊，真的？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"그래. 차라리 해변 끄트머리로 가 보려무나.","JPN":"そうじゃ。海辺の方へ行ってみたらどうじゃ。","ENG":"That's right. Why don't you check out the edge of the shoreline instead?","TWN":"是啊，妳要不要去海邊的盡頭看看。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"타지에서 온 낚시꾼들이 그리로 자주 가니까.","JPN":"その辺なら他所から来た釣り人がよくいるからの。","ENG":"A lot of the fishermen visiting from other regions flock there.","TWN":"外地來的垂釣者常去那裡呢。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"오오......! 고맙슴다, 할부지!","JPN":"おお……！　爺ちゃん、ありがとうっす！","ENG":"Oh! Thank you, sir!","TWN":"噢噢……！謝謝你，爺爺！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"......한참 기다려도 송사리 한 마리 안 보이지 말임다.","JPN":"……ずっと待ってるけど、メダカ1匹すら釣れないっす。","ENG":"... I've been fishin' forever and I haven't caught a thing.","TWN":"……釣了半天，連個小蝦米都沒有。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"이대로 빈손으로 돌아가면 아부지가 또 놀릴지도 모름다.","JPN":"このままボウズで帰ったら父ちゃんにまた笑われるっす。","ENG":"Papa will surely make fun of me again if I go back empty-handed.","TWN":"如果空手而回，爸爸一定又會笑我的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"<color=#ffd34c>하하! 우리 딸, 그 성격에 낚시 배우려면 백 년은 더 걸릴 걸?</color>","JPN":"<color=#ffd34c>ガハハハッ！　その調子じゃ、釣れるまであと100年はかかるぞ！</color>","ENG":"<color=#ffd34c>Hah hah! My impatient girl, it'll take another hundred years for you to learn how to fish properly!</color>","TWN":"<color=#ffd34c>哈哈！我的女兒，就妳那個性格也想學釣魚，至少還得一百年。</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"<color=#ffd34c>눈썹 씰룩씰룩.</color>","JPN":"<color=#ffd34c>(ドヤ顔)</color>","ENG":"<color=#ffd34c>And he'll wiggle his eyebrows.</color>","TWN":"<color=#ffd34c>眉毛抖啊抖。</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"으으! 당할 순 없슴다!","JPN":"む……！　このまま帰るわけにはいかないっす！","ENG":"Ugh! I'm not gonna let it come to that!","TWN":"啊啊！我可受不了！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"보란 듯이 월척을 낚아 가서 모네도 눈썹 씰룩씰룩거려 볼 검다!","JPN":"立派な大物釣って、モネだってドヤ顔してやりたいっす！","ENG":"I'll catch me a big fish, and show my old man that I too know how to wiggle my eyebrows!","TWN":"莫妮我一定要釣一條大魚，然後也像爸爸一樣抖眉毛！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"앗?! 손끝에 걸리는 이 무게......! 월척이 분명함다!","JPN":"あれっ！？　この指先の重い感覚は……！　大物に違いないっす！","ENG":"Huh?! I feel something heavy on the pole... It must be a huge catch!","TWN":"咦？！這個力量……！肯定是條大魚！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"저항해도 소용없슴다! 얌전히 우리 엄니 뱃속으로 들어가지 말임다!","JPN":"抵抗しても無駄っすよ！　大人しく我が家の晩ご飯になれっす！","ENG":"Resistance is futile, Mr. Fish! Come quietly to my mama's tummy!","TWN":"放棄抵抗！乖乖到我媽媽的肚子裡吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"해냈다~! 어떤 물고긴지 얼른 봐야겠슴다!","JPN":"やったー！　何が釣れたのか早く確認しないと！","ENG":"I did it! Lemme see what kind of fish I caught!","TWN":"我釣到了~！看看是什麼魚！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_MAID_Q_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"이, 인어가 진짜 있었슴다?!","JPN":"に、人魚って本当にいるんっすね！？","ENG":"M-mermaids are real?!","TWN":"原、原來真的有美人魚？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L45_1","type":"dialog","speaker":"DAD_MAID_NPC_NULL","text":{"KOREA":"아니, 이게 누구야? 고기 잡으러 갔다 사람 잡아 온 우리 딸 아냐?","JPN":"おや？　どちら様かと思ったら、魚を釣りに行って人を釣ってきたうちの娘じゃないか？","ENG":"Well, look who's here! If it isn't my daughter, the mermaid angler!","TWN":"喲，這不是去釣魚卻釣了個人回來的我的女兒嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MOM_MAID_NPC_NULL","text":{"KOREA":"당신은 애 좀 그만 놀려요. 아빠도 애도 왜 쌍으로 주책인가 몰라.","JPN":"ちょっとあなた、そんなにからかわないで。もうっ、お父さんもモネも、どっちもどっちなんだから。","ENG":"Stop teasing her, honey. Like father, like daughter. Both of you are such rascals.","TWN":"你不要再笑她了，怎麼大人和孩子都這麼幼稚呢。"},"stage":{"bg":"BLACK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MOM_MAID_NPC_NULL","text":{"KOREA":"모네야, 네가 해변에서 낚아 왔던 분 드실 것 좀 만들었단다. 다락방에다 조용히 두고 오렴.","JPN":"モネ、あんたが釣ってきた人に食事を用意したわ。部屋に行って渡してあげなさい。","ENG":"Mone, I made something to eat for the lady you... fished out of the sea. Please go set this quietly at the attic door.","TWN":"莫妮，我做了點吃的，妳送過去給妳在海邊釣到的人吧，悄悄放到閣樓就好。"},"stage":{"bg":"BLACK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MOM_MAID_NPC_NULL","text":{"KOREA":"많이 다치신 것 같으니까 조용히 가야 돼. 알겠지?","JPN":"大怪我で安静にする必要があるから、静かにしてあげるのよ。","ENG":"Try to be quiet. She seems to be very hurt. Okay?","TWN":"她好像傷的不輕，所以一定要安靜。知道了嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"넵! 잽싸게 다녀오겠슴다!","JPN":"はいっ！　すぐ置いてくるっすよ！","ENG":"Yes, ma'am! I'll make it quick!","TWN":"好！我馬上去！"},"stage":{"bg":"BLACK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"안녕하심까!","JPN":"こんちゃー！","ENG":"Greetings, ma'am!","TWN":"妳好！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"맛이 끝내 주는 울엄니표 스튜 배달 왔슴다! 일어나서 한 그릇 드셔 봅셔!","JPN":"我が家の絶品、母ちゃん特製のシチューを届けに来たっす！　さあさあ、ぜひ食べてくださいッす！","ENG":"I've brought you my mama's stew! The best of the best! Come have a taste!","TWN":"我幫妳送來了美味的媽媽牌濃湯！快起來喝一碗吧！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"얼레? 아까까지 침대에 누워 있었는데 어디로 가셨담까......?","JPN":"あれれ？　さっきまで横になっていたのにどこに行ったんっすかね？","ENG":"Huh? She was lying in the bed just now. Where did she go?","TWN":"咦？剛剛還在床上，怎麼不見了……？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_Q_NULL","text":{"KOREA":"신체를 결박해 두지 않아서 쉽게 기절시킬 수 있었군요.","JPN":"拘束されなかったおかげで、簡単に気絶させることができましたね。","ENG":"Fortunately for me, you've left me untied. So I could knock you out easily.","TWN":"妳沒有限制我的自由，所以我才能輕易弄暈妳。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_Q_NULL","text":{"KOREA":"왜 이런 곳에서 깨어났는지는 몰라도, 인상착의가 노출되었다면 곤란하겠어요.","JPN":"なぜこんな場所で目を覚ましたのかは分かりませんが、姿を見られては困ります。","ENG":"I don't know what I'm doing here, but I can't afford to have anyone identify me.","TWN":"雖然不知道我為什麼會在這裡醒來，但如果我的衣著長相暴露的話就麻煩了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_MAID_Q_NULL","text":{"KOREA":"죄송합니다. 하지만 덜 자란 잡초라도 제 얼굴을 본 이상......","JPN":"申し訳ございません。しかし未熟な雑草とはいえ私の顔を見られた以上……","ENG":"I'm sorry. You are just a little weed, but since you've seen my face...","TWN":"非常抱歉，雖然妳只是無名小卒，但既然看到了我的臉……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEADER_MAID_Q_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_Q_NULL","text":{"KOREA":"제 얼굴을 목격한 이상...... 어떻게 해야 되는 거였죠?","JPN":"私の顔を見られた以上……どうすればいいんでしたっけ？","ENG":"Since you've seen my face, I must... What am I supposed to do?","TWN":"看到我的臉之後……要怎麼處理呢？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"정신을 차리셔서 다행임다!","JPN":"お、気が付いてよかったっす！","ENG":"You're awake, ma'am! Thank goodness!","TWN":"妳醒了，太好了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_Q_NULL","text":{"KOREA":"기절한 것 아니었나요? 이렇게 빨리 깨어날 수 있을 리가......?","JPN":"気絶させたつもりですが、こんなに早く目覚めるはずは……？","ENG":"Didn't I knock you out? How did you manage to wake up so quickly?!","TWN":"妳不是暈倒了嗎？怎麼醒的這麼快……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"엣헴. 할부지들이 모네만큼 튼튼한 꼬마는 카운터 중에도 드물 거라고 하셨슴다.","JPN":"えっへん、おばあちゃんが言ってたっす。モネほど丈夫な子はカウンターにもめったにいないって。","ENG":"Ahem. The old men around here always say that I'm probably sturdier than most Counters.","TWN":"嘿嘿，爺爺們說過，像莫妮這麼勇健的小孩，即使在制裁者中也很少見呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"그보다 방금 슉 했다가 팍 나타나는 게 스파이 영화 주인공 같이 멋졌슴다!","JPN":"それより、さっきサッと動いてパッと現れたのが、まるでスパイ映画の主人公みたいでカッコよかったっす！","ENG":"Anyway, the way you just vanished and appeared again was awesome, ma'am. Like a super spy from the movies!","TWN":"不過，剛剛妳到處閃現的樣子真的很帥，就像間諜電影的主角！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"앗, 혹시 진짜 스파이심까?","JPN":"あっ、もしかして本物のスパイっすか？","ENG":"Oh! Are you actually a real spy?","TWN":"啊，難道妳真的是間諜？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_Q_NULL","text":{"KOREA":"아뇨. 그런 건 아닌 것 같아요.","JPN":"いいえ、そのような者ではないと思います。","ENG":"No. I don't think so.","TWN":"不，應該不是。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_Q_NULL","text":{"KOREA":"그저 베로니카라는 이름의 메이드였다는 것밖에는......","JPN":"ただ、ベロニカという名前のメイドだったということしか……","ENG":"All I remember is that I used to be a maid named Veronica.","TWN":"我只記得我叫貝洛妮卡，是個女僕……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"으음. 모네는 메이드란 말 처음 듣지 말임다.","JPN":"うーん、モネはメイドという言葉が初耳っす。","ENG":"Huh? What's a \\"maid?\\" I've never heard of that before. You mean like a mermaid?","TWN":"唔，莫妮第一次聽到女僕這個詞。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_Q_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"메이드란 주인의 뜻을 이루어 드리는 삶의 형태랍니다.","JPN":"メイドとはご主人様の望みを叶える生き方をする者です。","ENG":"A maid is someone who serves her master to do their bidding.","TWN":"女僕就是一生追隨主人，按照主人的意願而活的人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"헌신과 봉사에서 보람을 느끼는 존재라고 할 수 있죠.","JPN":"献身と奉仕にやりがいを感じる存在とも言えます。","ENG":"We derive a sense of fulfilment from our commitment and service.","TWN":"可以說是通過奉獻和犧牲來獲得價值的存在。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"오오...... 뭔지 몰라도 대단한 일인 것 같슴다.","JPN":"おお……よくわかんないけど凄い仕事っすね。","ENG":"Ooh. That sounds like a noble thing to do, whatever it is.","TWN":"哦哦……雖然我不太清楚，但好像很了不起的樣子。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"앗, 그럼 인어님이 여기 있다고 주인님한테 알려야 하지 않슴까? 걱정하고 계실 검다!","JPN":"あ、それじゃあ人魚様がここにいるとご主人様に知らせるべきじゃないっすか？　きっと心配しているはずっすよ！","ENG":"Oh! Then shouldn't you inform your master that their mer-maid is here? They must be worried sick!","TWN":"啊，那是不是該告訴您的主人，您在這裡呢？主人會擔心的！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그럴 수 있다면 좋겠지만......","JPN":"それが可能ならいいですが……","ENG":"I wish I could, but...","TWN":"雖然我也是那麼想的……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"연락처도, 주인님의 성함도 기억이 나지 않아요.","JPN":"連絡先も、ご主人様の名前も思い出せません。","ENG":"I can remember neither my master's name nor how to contact.","TWN":"但我不記得主人的聯繫方式和名字了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"엑, 이건 말로만 듣던 기억 상실......?","JPN":"ええー！　これは噂に聞く記憶喪失……？","ENG":"Oh! Is this what they call amnesia?","TWN":"額，難道這就是傳說中的失憶……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"설마, 아까 업고 계단 올라오다가 인어님 머리를 천장에 쿵 찧게 했는데 그것 때문임까......?","JPN":"もしかしてさっき人魚様をおんぶして階段を上る時、頭を天井にぶつけちゃったんすけど、そのせいっすかね……？","ENG":"Oh, no. I bumped your head on the ceiling while carrying you upstairs. Could that be it?","TWN":"我剛剛背您上來的時候，您的頭碰到天花板了，難道是因為這個才……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아니요. 기억을 잃은 건 더 이전의 일 같아요.","JPN":"いいえ。記憶を失くしたのはその前のことだと思います。","ENG":"No. I think I've been like this for much longer than that.","TWN":"不是，失憶好像是更早之前的事。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"휴유~ 다행임다.","JPN":"ふう～よかったっす。","ENG":"Phew, what a relief.","TWN":"呼~幸好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"그런데 다른 건 기억 안 나심까? 뭔가 단서가 있을지도 모름다!","JPN":"ところで他のことは覚えていないっすか？　手がかりが見つかるかもっす！","ENG":"Well, do you remember anything else, ma'am? Maybe there are more clues!","TWN":"那妳還記得什麼？說不定能找到線索！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"단서라면......","JPN":"手がかりならば……","ENG":"Clues, huh...","TWN":"線索……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇군요. 아마도 과거의 저는 소중한 무언가를 지키려 했던 것 같아요.","JPN":"そうですね。おそらく過去の私は大切な何かを守ろうとしたみたいです。","ENG":"You're right. It seems like I was trying to protect something precious to me in the past.","TWN":"對了，過去的我好像是要守護某個珍貴的東西。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"떠올리려고만 해도 가슴이 먹먹해지는 것을요.","JPN":"思い出すだけで、胸が締め付けられるような感覚になります。","ENG":"Something that makes me choke up inside when I think about it.","TWN":"我一想要記起來就覺得難受。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"으음...... 소중한 무언가......","JPN":"う～ん……大切な何か……","ENG":"Hmm... Something precious...","TWN":"嗯……珍貴的東西……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"아! 모네한테 좋은 방법이 생각 났슴다!","JPN":"そうだ！　モネにいい考えがあるっす！","ENG":"Oh! Mone just had a great idea!","TWN":"啊！莫妮想到了一個好辦法！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네? 어떤 방법이죠?","JPN":"どんな方法でしょう？","ENG":"Huh? What is it?","TWN":"嗯？什麼辦法？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"메이드님은 자기가 메이드란 건 기억하고 있지 않슴까.","JPN":"メイド様は自分がメイドということは覚えてるじゃないっすか。","ENG":"You remember that you used to be a maid, right?","TWN":"您不是說記得自己是女僕嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"그럼 메이드님한테는 메이드란 직업도 그 지키려던 것만큼 중요했을 검다.","JPN":"ということは、メイド様にはそのメイドという仕事も、守ろうとしたモノと同じくらい大切だったはずっす。","ENG":"Then maybe being a maid was as important as whatever you were trying to protect.","TWN":"那對於您來說，守護女僕這個職業，肯定和那個東西一樣重要。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"그러니까 예전처럼 열심히 메이드 일을 하다 보면 기억이 되돌아올지도 모름다!","JPN":"だから以前みたいに一生懸命メイドの仕事を続ければ、記憶が戻ってくるかもしれないっすよ！","ENG":"Which means you might get your memories back if you do what you did as a maid!","TWN":"所以，像以前那樣認真做好女僕的事，說不定就能想起來了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......그렇군요. 논리는 없어도 일리는 있게 들려요.","JPN":"……なるほど。論理的な考えではありませんが、\\n一理くらいはあるかもしれませんね。","ENG":"I see. I don't exactly follow the logic, but it seems to make sense.","TWN":"……是嗎。雖然沒有什麼邏輯，但好像有點道理。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"고마워요. 모네 양 덕분에 갈피를 잡을 수 있게 됐습니다.","JPN":"ありがとうございます、モネさん。おかげで、何をすればいいか見えてきました。","ENG":"Thank you, Ms. Mone. I think I know how to proceed now thanks to you.","TWN":"謝謝你，莫妮。多虧了你，我知道該怎麼做了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"혹시 제가 모네 양을 도울 일은 없을까요? 도와 준 은혜를 갚으면 좋겠어요.","JPN":"よろしければ私の方で、\\nモネさんをお手伝いできることはありませんか？\\n助けてもらった恩返しができればと思います。","ENG":"Is there anything I can help you with? I'd like to return the favor.","TWN":"我有沒有什麼可以幫到妳的？我想報答妳。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"진짜임까?!","JPN":"ホントっすか！？","ENG":"Really?!","TWN":"真的嗎？！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"그럼 저 모네, 같이 메이드 일을 하고 싶슴다!","JPN":"それじゃ、モネも一緒にメイドの仕事がしたいっす！","ENG":"Then I'd like to become a maid too!","TWN":"莫妮也想和妳一起當女僕！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네? 그거면 충분한가요?","JPN":"はい？　それでいいのですか？","ENG":"Huh? Is that really all you need?","TWN":"嗯？就這樣？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"물론임다! 모네는 예전부터 도시에 가서 일을 해보고 싶었슴다!","JPN":"もちろんっす！　モネはずっと前から都会で仕事がしてみたかったっす！","ENG":"Of course! Mone has always wanted to go work in the city, ma'am!","TWN":"當然！莫妮從以前開始就想去城市工作了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"그런데 같이 가줄 어른도 없고 가서 뭘 할지도 막막했지 말임다.","JPN":"でも連れていってくれる人がいなくて、都会のどこに行けば仕事が見つかるかも分からなくて困ってたんっす。","ENG":"But I had no grown-ups to take me, and I didn't know what I'd do once I got there.","TWN":"但是沒有大人陪我去，也不知道去那裡做什麼。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"하지만 메이드님이 같이 가주시면 걱정 없을 거 같슴다!","JPN":"メイド様が一緒に行ってくれたら心強いと思うっす！","ENG":"But I think I'll be okay if you go with me, ma'am!","TWN":"不過，如果您和我一起去的話，我就不用擔心了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"과찬입니다. 제 몸 하나 건사하기 급급한 실력인 걸요.","JPN":"身に余るお言葉です。自分のことで精一杯ではありますが。","ENG":"You're far too kind. I can barely keep myself safe right now.","TWN":"過獎了，其實我連自己都照顧不好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 모네 양이 그렇게 믿어 준다면 저도 부응해 드릴게요.","JPN":"モネさんがそこまで信頼してくれるのでしたら、私も応えてさしあげたいと思います。","ENG":"But since you believe in me so much, I must rise to the occasion.","TWN":"但既然莫妮這麼相信我，那我也不能讓妳失望。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"만세! 그럼 얼른 어부지랑 엄니한테도 메이드가 되겠다고 말씀드리겠슴다!","JPN":"やったー！　それじゃ父ちゃんと母ちゃんにもメイドになると話してくるっす！","ENG":"Hooray! Then I'll go tell mama and papa that I've decided to become a maid!","TWN":"萬歲！那我現在就去告訴爸媽我要去當女僕！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"도시에 가면 돈을 많~이 벌어다 엄니랑 아부지한테 배도 사 드릴 검다!","JPN":"都会へ出稼ぎに行って、お金持ちになったら父ちゃんと母ちゃんに大きい船を買ってあげたいっす！","ENG":"I'll make a ton of money in the city and buy my folks a boat!","TWN":"我要去城市賺很~多錢，然後為爸媽買艘大船！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"후훗. 정말 기운이 넘치는 아이네요.","JPN":"フフッ。本当に健気な子ですね。","ENG":"Hah hah, what an energetic child.","TWN":"哈哈，妳真是活力四射呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만......","JPN":"ですが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"죄송합니다. 하지만 덜 자란 잡초라도 제 얼굴을 본 이상......","JPN":"申し訳ございません。しかし未熟な雑草とはいえ私の顔を見られた以上……","ENG":"I'm sorry. You are just a little weed, but since you've seen my face...","TWN":"非常抱歉，雖然妳只是無名小卒，但既然看到了我的臉……"},"stage":{"bg":"SS_MAID_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>싹을 뽑아 버릴 수밖에.</color>","JPN":"<color=#ff3636>根ごと取り除くしかありません。</color>","ENG":"<color=#ff3636>I must pull you up.</color>","TWN":"<color=#ff3636>我只能斬草除根了。</color>"},"stage":{"bg":"SS_MAID_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 대체...... 뭘 지키고 싶었던 걸까요?","JPN":"私はいったい……何を守ろうとしていたのでしょう？","ENG":"What was it that I wanted to protect?","TWN":"我想守護的……到底是什麼呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"}]`);export{e as default};